import datetime
import users
import validators
import notifications as notif

def send_welcome_notification(username):
    notif.send_notification(username, "Welcome to the service!")

class UserService:
    def __init__(self):
        self.users = {}

    def register(self, username, password):
        error = validators.validate_username(username) or validators.validate_password(password)
        if error:
            raise ValueError(error)
        if username in self.users:
            raise ValueError("User already exists")
        self.users[username] = {"password": password, "registered_at": datetime.datetime.now()}
        send_welcome_notification(username)
        print(f"User {username} registered")

    def authenticate(self, username, password):
        if username not in self.users:
            return False
        if self.users[username]["password"] != password:
            return False
        return True

def perform_startup_tests():
    service = UserService()

    # Register users
    service.register("alice", "securepass123")
    service.register("bob", "password456")

    # Test authentication
    if service.authenticate("alice", "securepass123"):
        print("alice authenticated")
    else:
        print("alice not authenticated")

    if service.authenticate("alice", "wrongpass"):
        print("wrong password accepted")
    else:
        print("Wrong password correctly rejected")

    print("UserService started successfully")

if __name__ == "__main__":
    perform_startup_tests()
